import React, { useState } from 'react';
import {BrowserRouter as Router, Routes , Route} from 'react-router-dom';
import './App.css';
import PlayersList from './component/PlayersList';
import GameBord from './component/GameBord';
import Login from './component/Login';

const pages = { home: "home", game: "game" }

function App() {
  const [page, setPage] = useState(pages.home)
  const [playerName, setPlayerName] = useState("")
  const [cards, setCards] = useState({})
  const [players, setPlayers] = useState([])

  let savePalyerName = (name) => {
    setPlayerName(name)
  }
  let theList = () => {
    return <PlayersList players={players} />
  }

  let changePage = (newPage) => {
    setPage(newPage)
  }
  let saveInfo = (name, didWin) => {
    let playersList = []
    let isoldPlayer = false
    let w = 0
    for (let i = 0; i < players.length; i++) {
      if (players[i].name == name) {
        if (didWin) {
          w = ((players[i].wins) + 1)
          console.log(w)
          playersList.push({ name: players[i].name, games: players[i].games + 1, wins: w })
        }
        else
          playersList.push({ name: players[i].name, games: players[i].games + 1, wins: players[i].wins })
        isoldPlayer = true
      }
      else playersList.push({ name: players[i].name, games: players[i].games, wins: players[i].wins })
    }
    if (!isoldPlayer) {
      if (didWin)
        playersList.push({ name: name, games: 1, wins: 1 })
      else
        playersList.push({ name: name, games: 1, wins: 0 })
    }
    setPlayers(playersList)

  }




  let displayPage = () => {
    switch (page) {
      case pages.home:
        return <Login players={players} savePlayerName={savePalyerName} pages={pages} currentPage={changePage} theList={theList} />
      case pages.game:
        return <GameBord playerName={playerName} saveInfo={saveInfo} pages={pages} currentPage={changePage} theList={theList} />

    }
  }


  return (
    <div>
      {displayPage()}
    </div>)
}
export default App;
